package com.naenae.teacher.support;
import com.naenae.common.user.domain.User;import com.naenae.common.user.repository.UserRepository;import com.naenae.teacher.auth.security.CustomUserDetails;import org.springframework.security.core.Authentication;import org.springframework.stereotype.Controller;import org.springframework.web.bind.annotation.*;
@ControllerAdvice(annotations=Controller.class) public class TeacherViewAdvice {private final UserRepository users;public TeacherViewAdvice(UserRepository users){this.users=users;}@ModelAttribute("teacherName")public String teacherName(Authentication a){return name(a);}@ModelAttribute("teacherDisplayName")public String display(Authentication a){return name(a)+"쌤";}@ModelAttribute("teacherInitial")public String initial(Authentication a){String n=name(a);return n.isBlank()?"?":n.substring(0,1);}@ModelAttribute("teacherHasProfileImage")public boolean image(Authentication a){User u=user(a);return u!=null&&u.getProfileImageStoredName()!=null;}private String name(Authentication a){User u=user(a);if(u!=null){String n=u.getNickname();if(n!=null&&!n.isBlank())return n;if(u.getName()!=null&&!u.getName().isBlank())return u.getName();}return"선생님";}private User user(Authentication a){if(a!=null&&a.getPrincipal()instanceof CustomUserDetails d)return users.findById(d.getUser().getId()).orElse(d.getUser());return null;}}